code = """import json
import re

# Load the alive BRCA patients data
file_path = locals()['var_functions.query_db:20']
with open(file_path, 'r') as f:
    brca_data = json.load(f)

# Process to get barcodes and histological types
alive_brca_patients = []
for record in brca_data:
    desc = record.get("Patient_description", "")
    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', str(desc))
    if match and ("Alive" in desc):
        barcode = match.group(1)
        histological_type = record.get("histological_type", "Unknown")
        alive_brca_patients.append({
            "ParticipantBarcode": barcode,
            "histological_type": histological_type
        })

# Create a mapping of barcode to histological type
barcode_to_histotype = {p["ParticipantBarcode"]: p["histological_type"] for p in alive_brca_patients}

print("__RESULT__:")
print(json.dumps({
    "total_patients": len(alive_brca_patients),
    "barcode_to_histotype_sample": {k: barcode_to_histotype[k] for k in list(barcode_to_histotype.keys())[:5]}
}))"""

